#include <unistd.h>
#include <sys/stat.h>
#include <string.h>

int main(void) {
    const char *orig = "/tmp/kf_link_orig";
    const char *hard = "/tmp/kf_link_hard";
    const char *soft = "/tmp/kf_link_soft";

    unlink(hard);
    unlink(soft);
    unlink(orig);

    FILE *f = fopen(orig, "w");
    fprintf(f, "test");
    fclose(f);

    link(orig, hard);
    symlink(orig, soft);

    struct stat s1, s2;
    stat(orig, &s1);
    stat(hard, &s2);
    printf("Meme inode : %d\n", (s1.st_ino == s2.st_ino) ? 1 : 0);
    printf("Nlinks : %ld\n", (long)s1.st_nlink);

    char buf[256];
    ssize_t len = readlink(soft, buf, sizeof(buf) - 1);
    buf[len] = '\0';
    printf("Cible symlink : %s\n", buf);

    unlink(soft);
    unlink(hard);
    unlink(orig);
    return 0;
}

